// Serializes a string in the HTTP payload without a content-type header
TEST(RestJsonServerMalformedTest, RestJsonStringPayloadNoContentType) {
  RestJsonServer server(std::make_shared<RecordingHandler>());
  smithy::http::HttpRequest request;
  request.method = "POST";
  request.target = "/StringPayload";
  request.body = "rawstring";
  const smithy::http::HttpResponse response = server.Handler()(request);
  EXPECT_EQ(response.status, 415) << response.body;
  EXPECT_EQ(response.headers.Get("x-amzn-errortype").value_or("<missing>"), "UnsupportedMediaTypeException");
}

// Serializes a string in the HTTP payload without the expected content-type header
TEST(RestJsonServerMalformedTest, RestJsonStringPayloadWrongContentType) {
  RestJsonServer server(std::make_shared<RecordingHandler>());
  smithy::http::HttpRequest request;
  request.method = "POST";
  request.target = "/StringPayload";
  request.headers.Set("Content-Type", "application/json");
  request.body = "rawstring";
  const smithy::http::HttpResponse response = server.Handler()(request);
  EXPECT_EQ(response.status, 415) << response.body;
  EXPECT_EQ(response.headers.Get("x-amzn-errortype").value_or("<missing>"), "UnsupportedMediaTypeException");
}

// Serializes a string in the HTTP payload with an unstatisfiable accept header
TEST(RestJsonServerMalformedTest, RestJsonStringPayloadUnsatisfiableAccept) {
  RestJsonServer server(std::make_shared<RecordingHandler>());
  smithy::http::HttpRequest request;
  request.method = "POST";
  request.target = "/StringPayload";
  request.headers.Set("Accept", "application/json");
  request.headers.Set("Content-Type", "text/plain");
  request.body = "rawstring";
  const smithy::http::HttpResponse response = server.Handler()(request);
  EXPECT_EQ(response.status, 406) << response.body;
  EXPECT_EQ(response.headers.Get("x-amzn-errortype").value_or("<missing>"), "NotAcceptableException");
}

// When there is modeled output, the accept must be application/json
