  RestJsonServer server(std::make_shared<RecordingHandler>());
  smithy::http::HttpRequest request;
  request.method = "POST";
  request.target = "/MalformedContentTypeWithBody";
  request.headers.Set("content-type", "application/hal+json");
  request.body = "{}";
  const smithy::http::HttpResponse response = server.Handler()(request);
  EXPECT_EQ(response.status, 415) << response.body;
  EXPECT_EQ(response.headers.Get("x-amzn-errortype").value_or("<missing>"), "UnsupportedMediaTypeException");
